section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/security-supply-chain.json",
  "type": "object",
  "required": [
    "repo_id",
    "scanners_wired",
    "pre_commit_present",
    "ci_full_history_scan",
    "license_allowlist",
    "sbom_format",
    "auto_merge_policy",
    "owner"
  ],
  "properties": {
    "repo_id": {
      "type": "string",
      "description": "stable repo identifier (org/name)"
    },
    "scanners_wired": {
      "type": "array",
      "description": "non-empty subset of [gitleaks, detect-secrets, trivy, snyk, syft, dependabot]"
    },
    "pre_commit_present": {
      "type": "boolean",
      "description": "true if .pre-commit-config.yaml at repo root"
    },
    "ci_full_history_scan": {
      "type": "boolean",
      "description": "true if CI runs git fetch --unshallow before scan"
    },
    "license_allowlist": {
      "type": "array",
      "description": "non-empty subset of [MIT, Apache-2.0, BSD-3-Clause, MPL-2.0]"
    },
    "sbom_format": {
      "type": "string",
      "description": "enum: SPDX | CycloneDX"
    },
    "auto_merge_policy": {
      "type": "object",
      "description": "{patch:boolean, minor:boolean, major:boolean=false}"
    },
    "owner": {
      "type": "string",
      "description": "single named handle (no team / we)"
    }
  }
}
